#!/usr/bin/env node
/**
 * Lockfile completeness guard — catches the npm optional-dependency pruning
 * bug (npm/cli#4828) before it reaches CI/Docker.
 *
 * Background: several build-time deps (lightningcss, @rolldown/binding, ...)
 * declare per-platform native binaries as OPTIONAL dependencies. A valid
 * package-lock.json must contain a package node for EVERY one of them (npm
 * installs only the node matching the host os/cpu, but the lockfile still
 * records all of them). When the lockfile is regenerated by an older/buggy
 * npm on macOS, npm prunes the other-platform nodes out of the lockfile.
 *
 * The symptom is environment-dependent and sneaky:
 *   - npm 10.x (`npm ci` in the lint-and-build matrix, and most dev Macs)
 *     TOLERATES the missing optional nodes — install/build pass.
 *   - npm 11.x (`node:*-alpine` Docker image) is STRICT and aborts with
 *     `EUSAGE ... Missing: <pkg> from lock file`.
 * So a green PR can still produce a red Docker build on main. This guard
 * removes that gap by asserting npm's own invariant in the lint-and-build
 * job, on every push, with no network and no npm version dependence.
 *
 * Check: for every package recorded in the lockfile, every name in its
 * `optionalDependencies` must resolve to a package node in the lockfile
 * (using npm's node-resolution walk). Any unresolved name is exactly what
 * strict `npm ci` would reject.
 *
 * Fix when this fails: regenerate a COMPLETE lockfile with a current npm —
 *   npx npm@latest install --package-lock-only
 * then commit package-lock.json. (Do NOT "fix" a green-locally/red-in-CI
 * native-module error by editing the Dockerfile or CI.)
 */
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const lock = JSON.parse(readFileSync(join(root, 'package-lock.json'), 'utf8'));
const packages = lock.packages ?? {};
const present = new Set(Object.keys(packages));

// Resolve a dependency `name` required by the package at `fromPath`, following
// npm's lookup: nearest node_modules first, walking up to the root.
function resolveDep(fromPath, name) {
  let prefix = fromPath;
  for (;;) {
    const candidate = prefix
      ? `${prefix}/node_modules/${name}`
      : `node_modules/${name}`;
    if (present.has(candidate)) return candidate;
    if (prefix === '') return null;
    const idx = prefix.lastIndexOf('/node_modules/');
    prefix = idx === -1 ? '' : prefix.slice(0, idx);
  }
}

const missing = [];
for (const [path, meta] of Object.entries(packages)) {
  for (const name of Object.keys(meta.optionalDependencies ?? {})) {
    if (!resolveDep(path, name)) {
      missing.push({ owner: path || '(root)', name });
    }
  }
}

if (missing.length > 0) {
  console.error('\n✗ Lockfile completeness guard FAILED\n');
  console.error(
    'package-lock.json is missing nodes for optional dependencies that\n' +
      'strict `npm ci` (npm 11+, e.g. node:*-alpine Docker) requires:\n',
  );
  for (const { owner, name } of missing) {
    console.error(`  • ${owner} → missing "${name}"`);
  }
  console.error(
    '\nThis lockfile passes npm 10 but fails npm 11 `npm ci` with\n' +
      '"EUSAGE ... Missing: <pkg> from lock file". Regenerate a complete\n' +
      'lockfile and commit it:\n\n' +
      '  npx npm@latest install --package-lock-only\n\n' +
      'See scripts/check-native-deps.mjs for the full explanation.\n',
  );
  process.exit(1);
}

const optionalCount = Object.values(packages).reduce(
  (n, m) => n + Object.keys(m.optionalDependencies ?? {}).length,
  0,
);
console.log(
  `✓ Lockfile completeness guard passed (${optionalCount} optional-dependency ` +
    `reference(s) across ${present.size} package nodes all resolve).`,
);
